Yes. You can create an `ObservableObject` as a property of `AppDelegate`.

That is a valid structure, and it is often cleaner than making `AppDelegate` itself an `ObservableObject`.

The shape is:

```swift
@main
struct LexApp: App {
    @NSApplicationDelegateAdaptor(AppDelegate.self)
    private var appDelegate

    var body: some Scene {
        MenuBarExtra("Lex", systemImage: "keyboard") {
            LexMenu(model: appDelegate.model)
        }
    }
}

final class AppDelegate: NSObject, NSApplicationDelegate {
    let model = LexModel()

    func applicationDidFinishLaunching(_ notification: Notification) {
        model.start()
    }

    func applicationWillTerminate(_ notification: Notification) {
        model.stop()
    }
}

@MainActor
final class LexModel: ObservableObject {
    @Published private(set) var mode: InputMode = .telex
    @Published private(set) var isEnabled = false
    @Published private(set) var permissionStatus: PermissionStatus = .unknown

    func start() {
        // initialize engine, check permissions, start event tap
    }

    func stop() {
        // stop event tap, free engine
    }

    func setMode(_ mode: InputMode) {
        self.mode = mode
    }
}

struct LexMenu: View {
    @ObservedObject var model: LexModel

    var body: some View {
        Button(model.mode == .telex ? "✓ Telex" : "Telex") {
            model.setMode(.telex)
        }

        Button(model.mode == .literal ? "✓ Literal" : "Literal") {
            model.setMode(.literal)
        }
    }
}
```

## How this differs from `LexController`

This is mostly a naming/role question.

If the object is called `LexController` and owns all runtime behavior, then yes, it becomes the abstraction you wanted to avoid.

But if the object is only the **observable UI state**, it can be useful:

```text
AppDelegate
  owns lifecycle and runtime

LexModel / AppState
  owns observable menu state only
```

However, if `LexModel.start()` initializes the engine, starts the event tap, owns permissions, and handles synthetic input, then it is effectively the controller again.

So there are two possible designs.

## Option A: AppDelegate owns runtime, ObservableObject owns only UI state

This matches your simpler direction best.

```diagram
╭────────────────────────────╮
│ AppDelegate                │
│ NSApplicationDelegate      │
│                            │
│ owns runtime:              │
│ - Zig state                │
│ - event tap                │
│ - synthetic input          │
│ - permissions              │
│                            │
│ owns model:                │
│ - published mode           │
│ - published status         │
╰─────────────┬──────────────╯
              │ updates
              ▼
╭────────────────────────────╮
│ LexState / LexModel        │
│ ObservableObject           │
│ @Published mode            │
│ @Published isEnabled       │
│ @Published permission      │
╰─────────────┬──────────────╯
              │ observed by
              ▼
╭────────────────────────────╮
│ LexMenu                    │
╰────────────────────────────╯
```

Example:

```swift
@MainActor
final class LexState: ObservableObject {
    @Published var mode: InputMode = .telex
    @Published var isEnabled = false
    @Published var permissionStatus: PermissionStatus = .unknown
}

final class AppDelegate: NSObject, NSApplicationDelegate {
    let state = LexState()

    private var engineState: UnsafeMutableRawPointer?
    private var eventTap: CFMachPort?
    private var eventTapRunLoopSource: CFRunLoopSource?

    func applicationDidFinishLaunching(_ notification: Notification) {
        loadPreferences()
        initializeEngine()
        refreshPermissions()
        startEventTapIfEnabled()
    }

    func applicationWillTerminate(_ notification: Notification) {
        stopEventTap()
        destroyEngine()
        savePreferences()
    }

    @MainActor
    func setMode(_ mode: InputMode) {
        guard state.mode != mode else { return }

        state.mode = mode
        savePreferences()
        resetEngineComposition()
        applyModeToEngine()
    }

    @MainActor
    func toggleEnabled() {
        if state.isEnabled {
            stopEventTap()
            state.isEnabled = false
        } else {
            startEventTapIfPossible()
        }
    }
}
```

Menu:

```swift
struct LexMenu: View {
    let appDelegate: AppDelegate
    @ObservedObject var state: LexState

    var body: some View {
        Button(state.mode == .telex ? "✓ Telex" : "Telex") {
            appDelegate.setMode(.telex)
        }

        Button(state.mode == .literal ? "✓ Literal" : "Literal") {
            appDelegate.setMode(.literal)
        }

        Divider()

        Button(state.isEnabled ? "Disable" : "Enable") {
            appDelegate.toggleEnabled()
        }
    }
}
```

Wiring:

```swift
@main
struct LexApp: App {
    @NSApplicationDelegateAdaptor(AppDelegate.self)
    private var appDelegate

    var body: some Scene {
        MenuBarExtra("Lex", systemImage: "keyboard") {
            LexMenu(
                appDelegate: appDelegate,
                state: appDelegate.state
            )
        }
    }
}
```

This keeps lifecycle/runtime in `AppDelegate`, and uses the observable object only for SwiftUI updates.

## Option B: ObservableObject owns runtime

This is also valid:

```swift
final class AppDelegate: NSObject, NSApplicationDelegate {
    let model = LexModel()

    func applicationDidFinishLaunching(_ notification: Notification) {
        model.start()
    }

    func applicationWillTerminate(_ notification: Notification) {
        model.stop()
    }
}
```

But this means:

```text
LexModel = controller
```

It is not wrong, but it reintroduces the abstraction you said you want to avoid.

If you choose this, name it honestly. Either:

```swift
LexRuntime
```

or:

```swift
LexAppModel
```

But do not pretend it is only UI state if it owns the event tap and engine memory.

## Recommended for your direction

Use:

```swift
final class AppDelegate: NSObject, NSApplicationDelegate {
    let state = LexState()

    // private runtime fields live here
}
```

Where:

```swift
@MainActor
final class LexState: ObservableObject {
    @Published var mode: InputMode = .telex
    @Published var isEnabled = false
    @Published var permissionStatus: PermissionStatus = .unknown
}
```

Then:

- `AppDelegate` owns lifecycle and runtime;
- `LexState` owns only state visible to SwiftUI;
- `LexMenu` observes `LexState`;
- menu actions call `AppDelegate`.

That gives you SwiftUI reactivity without creating a controller abstraction.

