Use the exported C ABI values from `src/lex.h`:

```c
extern const size_t lex_state_size;
extern const size_t lex_state_alignment;

void lex_state_init(void *state);
void lex_add(void *state, uint8_t c);
void lex_backspace(void *state);
```

Swift should allocate raw memory using `lex_state_size` and `lex_state_alignment`, then pass that pointer to `lex_state_init`.

## Minimal AppDelegate version

```swift
@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {
    let appState = AppState()

    private var engineState: UnsafeMutableRawPointer?

    func applicationDidFinishLaunching(_ notification: Notification) {
        initializeEngine()
    }

    func applicationWillTerminate(_ notification: Notification) {
        destroyEngine()
    }

    private func initializeEngine() {
        precondition(engineState == nil)

        let byteCount = Int(lex_state_size)
        let alignment = Int(lex_state_alignment)

        let state = UnsafeMutableRawPointer.allocate(
            byteCount: byteCount,
            alignment: alignment
        )

        lex_state_init(state)

        engineState = state
    }

    private func destroyEngine() {
        guard let state = engineState else {
            return
        }

        state.deallocate()
        engineState = nil
    }
}
```

That is the core pattern.

## Why this is correct

The Zig side defines:

```zig
export const lex_state_size: usize = @sizeOf(State);
export const lex_state_alignment: usize = @alignOf(State);

export fn lex_state_init(state: *anyopaque) void {
    assert(@intFromPtr(state) != 0);
    assert(@intFromPtr(state) % @alignOf(State) == 0);

    const s: *State = @ptrCast(@alignCast(state));
    s.init();
}
```

So Swift must provide memory that is:

1. non-null;
2. at least `lex_state_size` bytes;
3. aligned to `lex_state_alignment`;
4. initialized by calling `lex_state_init`.

`UnsafeMutableRawPointer.allocate(byteCount:alignment:)` satisfies the allocation requirements.

## Using the engine after initialization

Always unwrap the pointer before calling the C ABI:

```swift
private func addAscii(_ byte: UInt8) {
    guard let state = engineState else {
        return
    }

    lex_add(state, byte)
}

private func backspaceEngine() {
    guard let state = engineState else {
        return
    }

    lex_backspace(state)
}
```

Example call:

```swift
addAscii(UInt8(ascii: "a"))
```

## Resetting the engine

With the current ABI, reset can reuse the same allocated memory:

```swift
private func resetEngine() {
    guard let state = engineState else {
        return
    }

    lex_state_init(state)
}
```

This works because the current Zig `State` appears to be plain internal state with `init()` resetting fields. If `State` later owns heap memory or external resources, add a C ABI function like:

```c
void lex_state_deinit(void *state);
```

Then Swift should call `lex_state_deinit(state)` before `deallocate()` or before reinitializing.

## Full small shape with menu action

```swift
@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {
    let appState = AppState()

    private var engineState: UnsafeMutableRawPointer?

    func applicationDidFinishLaunching(_ notification: Notification) {
        initializeEngine()
    }

    func applicationWillTerminate(_ notification: Notification) {
        destroyEngine()
    }

    func resetComposition() {
        guard let state = engineState else {
            return
        }

        lex_state_init(state)
    }

    func inputAscii(_ byte: UInt8) {
        guard let state = engineState else {
            return
        }

        lex_add(state, byte)
    }

    func inputBackspace() {
        guard let state = engineState else {
            return
        }

        lex_backspace(state)
    }

    private func initializeEngine() {
        precondition(engineState == nil)

        let byteCount = Int(lex_state_size)
        let alignment = Int(lex_state_alignment)

        let state = UnsafeMutableRawPointer.allocate(
            byteCount: byteCount,
            alignment: alignment
        )

        lex_state_init(state)
        engineState = state
    }

    private func destroyEngine() {
        guard let state = engineState else {
            return
        }

        state.deallocate()
        engineState = nil
    }
}
```

Important rule: Swift must not cast this pointer to a Swift `State` type or inspect Zig fields. Treat it as opaque memory and only use the exported functions.

